import re
from typing import List

# 与题面一致的单词切分规则
WORD_SPLIT = re.compile(r"[\s,.!?;:]+")


class Solution:
    def analyzeLogKeywords(self, logs: List[str], keywords: List[str]) -> List[int]:
        kws = [k.lower() for k in keywords]
        tokenized = [[w.lower() for w in WORD_SPLIT.split(log) if w] for log in logs]

        counts = [0] * len(keywords)
        for words in tokenized:
            for ki, kw in enumerate(kws):
                # 完整单词匹配，累加出现次数
                counts[ki] += sum(1 for w in words if w == kw)

        # 预处理每条日志出现了哪些关键词
        present = []
        for words in tokenized:
            word_set = set(words)
            present.append([kw in word_set for kw in kws])

        pairs: List[int] = []
        m = len(keywords)
        for i in range(m):
            for j in range(i + 1, m):
                co = sum(1 for row in present if row[i] and row[j])
                if co >= 2:
                    pairs.extend([i, j])

        return counts + pairs
```

```java
import java.util.ArrayList;

public class Solution {
    private static boolean isDelim(char c) {
        return Character.isWhitespace(c) || c == ',' || c == '.' || c == '!' ||
                c == '?' || c == ';' || c == ':';
    }

    private static ArrayList<String> tokenize(String log) {
        ArrayList<String> words = new ArrayList<>();
        StringBuilder cur = new StringBuilder();
        for (int i = 0; i < log.length(); i++) {
            char c = log.charAt(i);
            if (isDelim(c)) {
                if (cur.length() > 0) {
                    words.add(cur.toString().toLowerCase());
                    cur.setLength(0);
                }
            } else {
                cur.append(c);
            }
        }
        if (cur.length() > 0) words.add(cur.toString().toLowerCase());
        return words;
    }

    public int[] analyzeLogKeywords(String[] logs, String[] keywords) {
        int m = keywords.length;
        String[] kws = new String[m];
        for (int i = 0; i < m; i++) kws[i] = keywords[i].toLowerCase();

        int[] counts = new int[m];
        for (String log : logs) {
            ArrayList<String> words = tokenize(log);
            for (int ki = 0; ki < m; ki++) {
                for (String w : words) {
                    if (w.equals(kws[ki])) counts[ki]++;
                }
            }
        }

        ArrayList<Integer> pairs = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            for (int j = i + 1; j < m; j++) {
                int co = 0;
                for (String log : logs) {
                    ArrayList<String> words = tokenize(log);
                    boolean hasI = false, hasJ = false;
                    for (String w : words) {
                        if (w.equals(kws[i])) hasI = true;
                        if (w.equals(kws[j])) hasJ = true;
                    }
                    if (hasI && hasJ) co++;
                }
                // 至少 2 条不同日志共现才记录
                if (co >= 2) {
                    pairs.add(i);
                    pairs.add(j);
                }
            }
        }

        int[] ans = new int[m + pairs.size()];
        System.arraycopy(counts, 0, ans, 0, m);
        for (int i = 0; i < pairs.size(); i++) ans[m + i] = pairs.get(i);
        return ans;
    }
}
