var analyzeLogKeywords = function(logs, keywords) {
    // 分词：按空格及英文标点切分，转小写
    function tokenize(log) {
        return log.split(/[\s,.!?;:]+/).filter(function(w) { return w.length > 0; }).map(function(w) { return w.toLowerCase(); });
    }

    // 关键词转小写
    var kws = keywords.map(function(k) { return k.toLowerCase(); });
    var m = kws.length;

    // 统计每个关键词的总出现次数
    var counts = new Array(m).fill(0);
    for (var li = 0; li < logs.length; li++) {
        var words = tokenize(logs[li]);
        for (var ki = 0; ki < m; ki++) {
            for (var wi = 0; wi < words.length; wi++) {
                if (words[wi] === kws[ki]) counts[ki]++;
            }
        }
    }

    // 统计关键词共现对（至少 2 条日志共现才输出）
    var pairs = [];
    for (var i = 0; i < m; i++) {
        for (var j = i + 1; j < m; j++) {
            var co = 0;
            for (var li = 0; li < logs.length; li++) {
                var words = tokenize(logs[li]);
                var hasI = false, hasJ = false;
                for (var wi = 0; wi < words.length; wi++) {
                    if (words[wi] === kws[i]) hasI = true;
                    if (words[wi] === kws[j]) hasJ = true;
                }
                if (hasI && hasJ) co++;
            }
            if (co >= 2) pairs.push(i, j);
        }
    }

    return counts.concat(pairs);
};
