#include <stdlib.h>
#include <string.h>
#include <ctype.h>

// 判断是否是分词分隔符
static int isDelim(char c) {
    return isspace((unsigned char)c) || c == ',' || c == '.' ||
           c == '!' || c == '?' || c == ';' || c == ':';
}

// 字符串转小写
static void toLowerStr(char* s) {
    for (int i = 0; s[i]; i++) s[i] = (char)tolower((unsigned char)s[i]);
}

// 将日志分词为小写单词列表
static char** tokenize(const char* log, int* wordCount) {
    int cap = 1000;
    char** words = (char**)malloc(cap * sizeof(char*));
    *wordCount = 0;
    int len = (int)strlen(log);
    int curLen = 0;
    char cur[2000];

    for (int i = 0; i <= len; i++) {
        char c = log[i];
        if (c == '\0' || isDelim(c)) {
            if (curLen > 0) {
                cur[curLen] = '\0';
                toLowerStr(cur);
                words[*wordCount] = (char*)malloc(curLen + 1);
                strcpy(words[*wordCount], cur);
                (*wordCount)++;
                curLen = 0;
            }
        } else {
            cur[curLen++] = c;
        }
    }
    return words;
}

int* analyzeLogKeywords(char** logs, int logsSize, char** keywords, int keywordsSize, int* returnSize) {
    int m = keywordsSize;

    // 关键词转小写
    char** kws = (char**)malloc(m * sizeof(char*));
    for (int i = 0; i < m; i++) {
        kws[i] = (char*)malloc(strlen(keywords[i]) + 1);
        strcpy(kws[i], keywords[i]);
        toLowerStr(kws[i]);
    }

    // 统计每个关键词的总出现次数
    int* counts = (int*)calloc(m, sizeof(int));
    for (int li = 0; li < logsSize; li++) {
        int wc;
        char** words = tokenize(logs[li], &wc);
        for (int ki = 0; ki < m; ki++) {
            for (int wi = 0; wi < wc; wi++) {
                if (strcmp(words[wi], kws[ki]) == 0) counts[ki]++;
            }
        }
        for (int wi = 0; wi < wc; wi++) free(words[wi]);
        free(words);
    }

    // 统计关键词共现对（至少 2 条日志共现才输出）
    int pairCap = m * m * 2;
    int* pairs = (int*)malloc(pairCap * sizeof(int));
    int pairCount = 0;

    for (int i = 0; i < m; i++) {
        for (int j = i + 1; j < m; j++) {
            int co = 0;
            for (int li = 0; li < logsSize; li++) {
                int wc;
                char** words = tokenize(logs[li], &wc);
                int hasI = 0, hasJ = 0;
                for (int wi = 0; wi < wc; wi++) {
                    if (strcmp(words[wi], kws[i]) == 0) hasI = 1;
                    if (strcmp(words[wi], kws[j]) == 0) hasJ = 1;
                }
                if (hasI && hasJ) co++;
                for (int wi = 0; wi < wc; wi++) free(words[wi]);
                free(words);
            }
            if (co >= 2) {
                pairs[pairCount++] = i;
                pairs[pairCount++] = j;
            }
        }
    }

    // 组装结果：计数 + 关联下标对
    *returnSize = m + pairCount;
    int* result = (int*)malloc(*returnSize * sizeof(int));
    for (int i = 0; i < m; i++) result[i] = counts[i];
    for (int i = 0; i < pairCount; i++) result[m + i] = pairs[i];

    for (int i = 0; i < m; i++) free(kws[i]);
    free(kws);
    free(counts);
    free(pairs);
    return result;
}
